class UPPH_DAILY():
    def __init__(self):
        self.url = 'http://localhost:8083/other/upph/'

    def status_link(self):
        global main_url
        if requests.get(self.url).status_code != 200:
            print('FAIL')
            main_url = pp_url()[0]
            return main_url
        else:
            # print('PASS')
            return main_url

    def qty_hr1(self, em: int, shift: str) -> float:
        """
        获取总工时函数
        :param em: 人数
        :param shift: 班别
        :return: 工时
        """
        # 获取当前时间
        current_time = datetime.now()
        if shift == 'D':
            past_time = datetime.now().replace(hour=8, minute=0, second=0, microsecond=0)
            end_time_d = datetime.now().replace(hour=19, minute=40, second=0, microsecond=0)
            if current_time >= end_time_d:
                # qty_hr = round((end_time_d - past_time).total_seconds() * em // 3600) - em * 1.66
                qty_hr = em*10
            # 大于19:00每人减掉0.66H
            elif int(str(current_time).split(' ')[1][0:2]) > 19:
                # 计算时间差（以小时为单位，向下取整） 时差乘以人力整除3600秒计算总工时
                qty_hr = round(
                    (current_time - past_time).total_seconds() * em // 3600) - em * 0.66
            # 大于16:00每人减掉1.66H
            elif int(str(current_time).split(' ')[1][0:2]) > 16:
                qty_hr = round(
                    (current_time - past_time).total_seconds() * em // 3600) - em * 1.66
            # 大于12:00每人减掉1H
            elif int(str(current_time).split(' ')[1][0:2]) >= 12:
                qty_hr = round(
                    (current_time - past_time).total_seconds() * em // 3600) - em * 1
            else:
                qty_hr = round(
                    (current_time - past_time).total_seconds() * em // 3600)
                if qty_hr == 0:
                    return 1
        else:
            past_time = datetime.now().replace(hour=20, minute=0, second=0, microsecond=0)
            # # 获取当前时间
            # current_time = datetime.now()
            end_time_n = datetime.now().replace(hour=7, minute=40, second=0, microsecond=0)
            if round((current_time - past_time).total_seconds()) < 0:
                if current_time >= end_time_n:
                    # qty_hr = (round((end_time_n - past_time).total_seconds() + 24 * 3600) * em // 3600) - em * 1.66
                    qty_hr = em*10
                # 大于7:00每人减掉0.66H
                elif int(str(current_time).split(' ')[1][0:2]) > 7:
                    # 计算时间差（以小时为单位，向下取整） 时差乘以人力整除3600秒计算总工时
                    qty_hr = (round(
                        (current_time - past_time).total_seconds() + 24 * 3600) * em // 3600) - em * 0.66
                # 到达05:00每人减掉1.66H
                elif int(str(current_time).split(' ')[1][0:2]) > 4:
                    qty_hr = (round(
                        (current_time - past_time).total_seconds() + 24 * 3600) * em // 3600) - em * 1.66
                # 到达01:00每人减掉1H
                elif int(str(current_time).split(' ')[1][0:2]) >= 0:
                    qty_hr = (round(
                        (current_time - past_time).total_seconds() + 24 * 3600) * em // 3600) - em * 1
                else:
                    qty_hr = (
                        round((current_time - past_time).total_seconds() + 24 * 3600) * em // 3600)
            else:
                qty_hr = round(
                    (current_time - past_time).total_seconds() * em // 3600)
                if qty_hr == 0:
                    return 1
        return qty_hr

