    def upph(self, hr, line, shift, station):
        """
        获取实际的UPPH
        :param hr: 人数
        :param line: 线别
        :param station: 站别
        :return: 产量,工时,UPPH
        """
        em = int(hr)
        qty_hr = self.qty_hr1(em, shift)
        product_qty = self.qcm(line, shift, station)
        upph = round(product_qty / qty_hr, 2)
        # print(f'当前SUB_UPPH为：{sub_upph}')
        data = {
            'product_qty': product_qty,
            'qty_hr': round(qty_hr, 2),
            'upph': upph,
            # 'diff_hours': diff_hours
        }
        print(f'{line}:', data)
        return data


